-- PHES Job History Import
-- Source: MaidCentral Dispatch Board exports
-- Coverage: Jan 10, 2025 - Mar 24, 2026
-- Total records: 3953

CREATE TABLE IF NOT EXISTS job_history (
  id SERIAL PRIMARY KEY,
  company_id INTEGER NOT NULL DEFAULT 1,
  mc_job_id TEXT UNIQUE,
  customer_name TEXT,
  customer_id INTEGER,
  address TEXT,
  frequency TEXT,
  scheduled_date DATE,
  scheduled_start TEXT,
  scheduled_end TEXT,
  team TEXT,
  actual_start TEXT,
  actual_end TEXT,
  actual_hours DECIMAL(6,2),
  allowed_hours DECIMAL(6,2),
  team_size INTEGER DEFAULT 1,
  billing_type TEXT,
  bill_rate DECIMAL(10,2),
  billing_terms TEXT,
  status TEXT DEFAULT 'closed',
  scorecard_score INTEGER,
  source TEXT DEFAULT 'mc_import',
  imported_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_jh_company ON job_history(company_id);
CREATE INDEX IF NOT EXISTS idx_jh_customer ON job_history(customer_id);
CREATE INDEX IF NOT EXISTS idx_jh_date ON job_history(scheduled_date);

