-- After import, match customers by name
UPDATE job_history jh
SET customer_id = c.id
FROM customers c
WHERE jh.company_id = 1
AND jh.customer_id IS NULL
AND LOWER(TRIM(jh.customer_name)) = LOWER(TRIM(c.first_name || ' ' || c.last_name));

-- Verify
SELECT 
  COUNT(*) as total_jobs,
  COUNT(customer_id) as matched_to_customer,
  MIN(scheduled_date) as earliest_job,
  MAX(scheduled_date) as latest_job,
  SUM(bill_rate) as total_revenue
FROM job_history WHERE company_id = 1;
